-- ============================================================
-- data.sql - Datos de prueba para demo
-- Se ejecuta automáticamente al levantar la app (DatabaseInitializationConfig)
-- IMPORTANTE: como hibernate.hbm2ddl.auto=create, las tablas se
-- recrean vacías en cada arranque, así que estos INSERT siempre
-- parten de cero. No hace falta WHERE NOT EXISTS acá.
-- ============================================================

