-- ---------------------------
-- SUBASTAS
-- ---------------------------
-- estadoSubasta es un enum guardado como ORDINAL:
--   0 = ACTIVA, 1 = CUENTA_ATRAS, 2 = CERRADA
-- La columna imagen queda en NULL acá; se completa después
-- con UPDATEs generados por el script convertir_imagen.py
-- (ver instrucciones más abajo).
--
-- IMPORTANTE PARA LA DEMO DE RECOMENDACIÓN:
-- El prompt de Gemini arma el historial del usuario a partir de las
-- CATEGORÍAS de las subastas en las que pujó, y solo puede recomendar
-- entre subastas ACTIVAS. Por eso acá hay 2 subastas activas en "Hogar"
-- y 2 activas en "Deporte" -- así el usuario3 (que pujó en reloj y
-- bicicleta) tiene candidatas reales para que le recomienden.

INSERT INTO Subasta
  (id, nombre, descripcion, categoria, estadoArticulo, imagen,
   estadoSubasta, fechaCierre, precioInicial, precioActual, precioMaximo, creador_id)
VALUES
-- Subasta 1: ACTIVA (Hogar), tiene ofertas y una autopuja
(1, 'Reloj antiguo de pared', 'Reloj de péndulo en madera, funcionando correctamente', 'Hogar', 'Usado', X'',
 0, '2026-08-15 18:00:00', 10000, 18000, 50000, 1),

-- Subasta 2: ACTIVA (Deporte), con oferta y autopuja
(2, 'Bicicleta de montaña', 'Rodado 29, cambios Shimano, poco uso', 'Deporte', 'Usado', X'',
 0, '2026-08-20 20:00:00', 50000, 90000, 200000, 1),

-- Subasta 3: ACTIVA (Electronica), creada por otro usuario (usuario 2), con una oferta
(3, 'Consola de videojuegos retro', 'Consola de los 90 con dos joysticks y 5 cartuchos', 'Electronica', 'Usado', X'',
 0, '2026-08-10 19:00:00', 30000, 45000, 100000, 2),

-- Subasta 4: ACTIVA (Hogar), sin ofertas -- candidata de recomendación para quien pujó por el reloj
(4, 'Lámpara de living', 'Lámpara de pie con pantalla de tela, muy buen estado', 'Hogar', 'Usado', X'',
 0, '2026-08-18 20:00:00', 20000, 20000, 80000, 1),

-- Subasta 5: ACTIVA (Deporte), sin ofertas -- candidata de recomendación para quien pujó por la bici
(5, 'Pelota de fútbol profesional', 'Pelota reglamentaria, nueva, con caja', 'Deporte', 'Nuevo', X'',
 0, '2026-08-22 20:00:00', 15000, 15000, 60000, 1),

-- Subasta 6: CERRADA (Electronica), con historial completo de ofertas -- para mostrar una subasta finalizada
(6, 'Auriculares inalámbricos', 'Auriculares con cancelación de ruido, poco uso', 'Electronica', 'Usado', X'',
 2, '2026-07-01 18:00:00', 40000, 60000, 100000, 1),

-- Subasta 7: CUENTA_ATRAS (Arte), sin ofertas -- para mostrar el timer de cierre próximo
(7, 'Cuadro al óleo paisaje', 'Pintura original enmarcada, técnica óleo sobre tela', 'Arte', 'Usado', X'',
 1, '2026-07-16 12:00:00', 20000, 20000, 80000, 1);

 -- Subasta 8: ACTIVA (Hogar) -- segunda candidata nueva de recomendación en Hogar
(8, 'Juego de vajilla de porcelana', 'Vajilla completa para 12 personas, sin uso', 'Hogar', 'Nuevo', X'',
 0, '2026-08-19 20:00:00', 25000, 25000, 90000, 1),

-- Subasta 9: ACTIVA (Deporte) -- segunda candidata nueva de recomendación en Deporte
(9, 'Raqueta de tenis profesional', 'Raqueta de grafito, encordada, funda incluida', 'Deporte', 'Nuevo', X'',
 0, '2026-08-23 20:00:00', 18000, 18000, 70000, 1);

-- ---------------------------
-- OFERTAS (pujas)
-- ---------------------------
-- OJO: usuario3 puja en Hogar (subasta 1) y en Deporte (subasta 2).
-- Ese es el usuario ideal para mostrar la demo de recomendación:
-- al pedirle sugerencias, debería recibir la lámpara (4) y/o la pelota (5).
INSERT INTO Oferta (id, monto, subasta_id, usuario_id) VALUES
(1, 15000, 1, 2),   -- usuario2 puja reloj
(2, 18000, 1, 3),   -- usuario3 supera la puja del reloj (historial: Hogar)
(3, 90000, 2, 3),   -- usuario3 puja bicicleta (historial: Deporte)
(4, 45000, 3, 4),   -- usuario4 puja consola
(5, 40000, 6, 2),   -- historial subasta cerrada (auriculares)
(6, 60000, 6, 3);   -- oferta ganadora de la subasta cerrada

